// Script Continued Below
var TaskerWidgetIconsAndMessages = Class.create();
TaskerWidgetIconsAndMessages.prototype = {
    initialize: function(widgetId) {
		this.widgetId = widgetId;
		this.taskerFormPreferences = new tasker_User_Form_Preferences();
		this.PREFERENCE_FAVORITE = 'DT.Tasker.FavoriteOU';
		// STRY0121023 
		this.PREFERENCE_FAVORITE_STOP_PROMPT = 'DT.Tasker.FavoriteOU.StopPrompt';
		// STRY0121017 
		this.PREFERENCE_DEFAULT_STOP_PROMPT = 'DT.Tasker.DefaultOU.StopPrompt';

		this.PREFERENCE_PERCENT= 'DT.' + widgetId + '.scale';
		// STRY0117951
		this.PREFERENCE_TREE_ORIENTATION = 'DT.' + widgetId + '.direction';
		// STRY0119569 - this constant is in tasker_User_Form_Preferences 
		// - all of these should go into a constants script include 
		this.PREFERENCE_DEFAULT_TASK_FORM_VIEW = this.taskerFormPreferences.PREFERENCE_DEFAULT_TASK_FORM_VIEW;
		// STRY0118963
		this.ORG_USER_DEFAULT_PAGE_ID = 'DTechApps.Tasker.org_default_page_id';
		// STRY0121807 - STRY0121809 - get user default landing page
		this.USER_DEFAULT_LANDING_PAGE = "DTechApps.Tasker.user_default_landing_page";
		// STRY0121811 - get user default filter
		this.USER_DEFAULT_MAIN_FILTER = "DTechApps.Tasker.user_default_main_filter";
		this.topId = "";
    },
	// STRY0121782 - STRY0121780 - STRY0125624
	setTopId: function (topId){
		// top id used to store tree preferences per top id
		this.topId = topId;
	},

	// STRY0121782 - STRY0121780 - STRY0125624
	getTopId: function (){
		// top id used to store tree preferences per top id
		return this.topId;
	},	
	// this loads all TaskerWidgetMessage and titles that are not part of icons
	loadMessages: function() {
		var widgetMessages;
		switch (this.widgetId){
			// STRY0121797
			case 'tasker_banner_menu':
				widgetMessages = this._load_tasker_banner_menu_widgetMessages();
				break;
			// STRY0121339
			case 'tasker_home_icon':
				widgetMessages = this._load_tasker_home_widgetMessages();
				break;
			// STRY0121807  - STRY0121809 - STRY0121811 
			case 'tasker_portal_board_with_filter':
				widgetMessages = this._load_tasker_portal_board_with_filter_widgetMessages();
				break;
			case 'tasker_count':
				widgetMessages = this._load_tasker_count_widgetMessages();
				break;
			// STRY0118963 
			case 'tasker-header-menu':
				widgetMessages = this._load_tasker_header_menu_widgetMessages();
				break;
			// STRY0119569 
			case 'new_tasker_selection':
				widgetMessages = this._load_new_tasker_selection_widgetMessages();
				break;
			// 'discovertasker-officehierarchy-header' - NO MESSAGES - goes to default
			case 'discovertasker-officehierarchy':
				widgetMessages = this._load_officehierarchy_widgetMessages();
				break;
			case 'discovertasker-officehierarchy-footer':
				widgetMessages = this._load_ORG_toolTip_footer_widgetMessages();
				break;
			// 'discovertasker-processtemplatetreegraph-header' - NO MESSAGES  - goes to default
			case 'discovertasker-processtemplatetreegraph':	
				widgetMessages = this._load_templatetree_widgetMessages();
				break;
			case 'discovertasker-processtemplatetreegraph-footer':	
				widgetMessages = this._load_toolTip_footer_widgetMessages();
				break;
			// 'discovertasker-recursivetasktreegraph-header' - NO MESSAGES  - goes to default
			case 'discovertasker-recursivetasktreegraph':	
				widgetMessages = this._load_tasktree_widgetMessages();
				break;
			case 'discovertasker-recursivetasktreegraph-footer':	
				widgetMessages = this._load_toolTip_footer_widgetMessages();
				break;
			case 'discovertasker_dynamic_breadcrumbs':
				widgetMessages = this._load_breadcrumbs_widgetMessages();
				break;
			case 'discovertasker-widget-in-modal':
				widgetMessages = this._load_widgetInModal_widgetMessages();
				break;
			default: 
				widgetMessages = {};
				break;
		}
		return widgetMessages;
	},

	// this loads all icons, alt tags and text used in icon tooltips
	loadIcons: function() {
		var icons = {};
		switch (this.widgetId){
			// STRY0121797
			case 'tasker_banner_menu':
				icons = this._load_tasker_banner_menu_icons(icons);
				break;
			// STRY0121339
			case 'tasker_home_icon':
				icons = this._load_tasker_home_icons(icons);
				break;
			// STRY0121807  - STRY0121809 - STRY0121811
			case 'tasker_portal_board_with_filter':
				icons = this._load_tasker_portal_board_with_filter_icons(icons);
				break;
			case 'tasker_count':
				icons = this._load_tasker_count_icons(icons);
				break;
			// STRY0118963
			case 'tasker-header-menu':
				icons = this._load_tasker_header_menu_icons(icons);
				break;
			case 'discovertasker-officehierarchy-header':
				icons = this._load_office_tree_header_icons(icons);
				break;
			case 'discovertasker-officehierarchy':
				// DFCT0010944
				icons = this._load_officehiearachy_icons(icons);
				break;
			case 'discovertasker-officehierarchy-footer':
				icons = this._load_ORG_toolTip_footer_icons(icons);
				// icons for footer are now different for task and template, moved old items into the org footer
				// icons = this._load_tree_footer_icons(icons);
				break;
			case 'discovertasker_dynamic_breadcrumbs':
				icons = this._load_breadcrumb_icons(icons);
				break;
			case 'discovertasker-widget-in-modal':
				icons = this._load_widgetInModal_icons(icons);
				break;
			case 'discovertasker-recursivetasktreegraph-header':	
				// DFCT0010944
				icons = this._load_task_tree_header_icons(icons);
				break;
			case 'discovertasker-recursivetasktreegraph':
				// no icons yet, all font awesome
				break;
			case 'discovertasker-recursivetasktreegraph-footer':
				icons = this._load_tree_footer_icons(icons);
				break;
			case 'discovertasker-processtemplatetreegraph-header':	
				// DFCT0010944
				icons = this._load_template_tree_header_icons(icons);
				break;
			case 'discovertasker-processtemplatetreegraph':
				// no icons yet, all font awesome
				break;
			case 'discovertasker-processtemplatetreegraph-footer':
				icons = this._load_tree_footer_icons(icons);
				break;
		}
		return icons;
	},

	loadDefaultsAndSettings: function($sp){
		var settings;
		switch (this.widgetId){
			// STRY0121797
			case 'tasker_banner_menu':
				settings = this._load_tasker_banner_menu_defaultsAndSettings($sp);
				break;				
			// STRY0121339
			case 'tasker_home_icon':
				settings = this._load_tasker_home_defaultsAndSettings($sp);
				break;
			// STRY0121807  - STRY0121809 - STRY0121811
			case 'tasker_portal_board_with_filter':
				settings = this._load_tasker_portal_board_with_filter_defaultsAndSettings($sp);
				break;
			case 'tasker_count':
				settings = this._load_tasker_count_defaultsAndSettings($sp);
				break;
			// STRY0118963
			case 'tasker-header-menu':
				settings = this._load_tasker_header_menu_defaultsAndSettings($sp);
				break;
			// STRY0119569 
			case 'new_tasker_selection':
				settings = this._load_new_tasker_selection_defaultsAndSettings();
				break;
			case 'discovertasker-officehierarchy-header':
				settings = this._load_tree_header_defaultsAndSettings($sp);
				break;
			case 'discovertasker-officehierarchy':
				settings = this._load_officehierarchy_defaultsAndSettings($sp);
				settings = this._load_ORG_tooltip_footer_defaultsAndSettings(settings, $sp);
				break;
			case 'discovertasker-officehierarchy-footer':
				// need OU additional settings here
				settings = this._load_tree_footer_defaultsAndSettings();
				settings = this._load_ORG_tooltip_footer_defaultsAndSettings(settings, $sp);
				break;
			case 'discovertasker-recursivetasktreegraph-header':	
				settings = this._load_tree_header_defaultsAndSettings($sp);
				break;
			case 'discovertasker-recursivetasktreegraph':
				settings = this._load_tasktree_defaultsAndSettings($sp);
				break;
			case 'discovertasker-recursivetasktreegraph-footer':
				settings = this._load_tree_footer_defaultsAndSettings();
				break;
			case 'discovertasker-processtemplatetreegraph-header':	
				settings = this._load_tree_header_defaultsAndSettings($sp);
				break;
			case 'discovertasker-processtemplatetreegraph':
				settings = this._load_template_defaultsAndSettings($sp);
				break;
			case 'discovertasker-processtemplatetreegraph-footer':
				settings = this._load_tree_footer_defaultsAndSettings();
				break;
		}
		return settings;
	},

	// STRY0121807 - STRY0121809 - get user default landing page
	getPreferenceUserDefaultLandingPage: function(){
		var userDefaultLandingPage = gs.getUser().getPreference(this.USER_DEFAULT_LANDING_PAGE);
		return userDefaultLandingPage;
	},

	savePreferenceUserDefaultLandingPage: function(userDefaultLandingPage){
		gs.getUser().savePreference(this.USER_DEFAULT_LANDING_PAGE, userDefaultLandingPage);
	},

	// STRY0121811 - get user default filter
	getPreferenceUserDefaultMainFilter: function(page_filter){
		var userDefaultMainFilter = gs.getUser().getPreference(this.USER_DEFAULT_MAIN_FILTER + page_filter);
		return userDefaultMainFilter;
	},

	savePreferenceUserDefaultMainFilter: function(page_filter, userDefaultMainFilter){
		gs.getUser().savePreference(this.USER_DEFAULT_MAIN_FILTER + page_filter, userDefaultMainFilter);
	},

	// STRY0118963
	getPreferenceOrgUserDefaultPageId: function(){
		var orgUserDefaultPageId = gs.getUser().getPreference(this.ORG_USER_DEFAULT_PAGE_ID);
		return orgUserDefaultPageId;
	},

	savePreferenceOrgUserDefaultPageId: function(defaultOrgPageId){
		gs.getUser().savePreference(this.ORG_USER_DEFAULT_PAGE_ID, defaultOrgPageId);
	},

	// STRY0119569 
	savePreferenceDefaultTaskFormView: function(defaultTaskFormView){
		gs.getUser().savePreference(this.PREFERENCE_DEFAULT_TASK_FORM_VIEW, defaultTaskFormView);
	},

	// STRY0117951
	savePreferenceOrientation: function(newTreeOrientation){
		var treePreference = this.PREFERENCE_TREE_ORIENTATION + "." + this.getTopId();
		gs.getUser().savePreference(treePreference, newTreeOrientation);	
	},

	savePreferencePercent: function(newPercent){
		var treePercent = this.PREFERENCE_PERCENT + "." + this.getTopId();
		gs.getUser().savePreference(treePercent, newPercent);	
	},

	savePreferenceFavorite: function(newFavorite){
		gs.getUser().savePreference(this.PREFERENCE_FAVORITE, JSON.stringify(newFavorite));	
	},	

	// STRY0121023 
	savePreferenceFavoriteStopPrompt: function(){
		gs.getUser().savePreference(this.PREFERENCE_FAVORITE_STOP_PROMPT, true);	
	},	

	// STRY0121017 
	savePreferenceDefaultStopPrompt: function(){
		gs.getUser().savePreference(this.PREFERENCE_DEFAULT_STOP_PROMPT, true);	
	},	

	// load the filter page or set the default
	_getFilterPage: function($sp){
		var page_filter;
		page_filter = $sp.getParameter('page_filter') || '';
		if(page_filter == ''){
			// page not set on URL, look up in user preferences
			userDefaultLandingPage = gs.getUser().getPreference(this.USER_DEFAULT_LANDING_PAGE);
			if(userDefaultLandingPage){
				// if found, return
				page_filter = userDefaultLandingPage;
			} else {
				// return the default
				page_filter = 'my_task_home_page';
			}
		}
		return page_filter;
	},
	// load currently selected filter
	_getSelectedFitlerTitle: function(page_filter){
		var defaultMainFilter;
		if(page_filter == 'my_task_home_page'){
			var userDefaultTaskMainFilter = gs.getUser().getPreference(this.USER_DEFAULT_MAIN_FILTER + 'my_task_home_page');
			if(userDefaultTaskMainFilter){
				defaultMainFilter = userDefaultTaskMainFilter;
			} else {
				// leave this undefined so the default is set in control
				defaultMainFilter = "My Active Tasks";
			}
		} else if(page_filter == 'my_ous_tasks_home_page'){
			var userDefaultTaskOUMainFilter = gs.getUser().getPreference(this.USER_DEFAULT_MAIN_FILTER + 'my_ous_tasks_home_page');
			if(userDefaultTaskOUMainFilter){
				defaultMainFilter = userDefaultTaskOUMainFilter;
			} else {
				// leave this undefined so the default is set in control
				defaultMainFilter = "My OU's Active Tasks";
			}		
		}
		return defaultMainFilter;
	},

	// STRY0121797
	// ------------------------------------------------------------------------------------------------------------------
	// BEGIN -  Tasker Banner Menu
	// ------------------------------------------------------------------------------------------------------------------	
	_load_tasker_banner_menu_widgetMessages: function(){
		var widgetMessages = {};
		return widgetMessages;
	},
	_load_tasker_banner_menu_icons: function(icons){
		icons["TaskManager24.svg"] = this._buildIcon({imageName: 'TaskManager24.svg', title: gs.getMessage("Tasker - TaskManager24.svg"), alt: ""});
		icons["OrgHierarchyRequests24.svg"] = this._buildIcon({imageName: 'OrgHierarchyRequests24.svg', title: gs.getMessage("Tasker - OrgHierarchyRequests24.svg"), alt: ""});
		icons["TaskAdministrator24.svg"] = this._buildIcon({imageName: 'TaskAdministrator24.svg', title: gs.getMessage("Tasker - TaskAdministrator24.svg"), alt: ""});
		icons["TaskRequests24.svg"] = this._buildIcon({imageName: 'TaskRequests24.svg', title: gs.getMessage("Tasker - TaskRequests24.svg"), alt: ""});
		icons["Task24.svg"] = this._buildIcon({imageName: 'Task24.svg', title: gs.getMessage("Tasker - Task24.svg"), alt: ""});
		return icons;
	},
	_load_tasker_banner_menu_defaultsAndSettings: function($sp){
		settings = {};
		settings.baseURL = gs.getProperty('glide.servlet.uri');
		if($sp.getPortalRecord()){
			settings.service_portal_url_suffix = $sp.getPortalRecord().getValue('url_suffix');
		} else {
			// TODO: May want to pull default from the form load here
			settings.service_portal_url_suffix = '';
		}
		return settings;
	},
	// ------------------------------------------------------------------------------------------------------------------
	// END  - Tasker Banner Menu
	// ------------------------------------------------------------------------------------------------------------------	

	// STRY0121339
	// ------------------------------------------------------------------------------------------------------------------
	// BEGIN - Tasker Home Icon
	// ------------------------------------------------------------------------------------------------------------------	
	_load_tasker_home_widgetMessages: function(){
		var widgetMessages = {};
		widgetMessages['Tasker - Home'] = gs.getMessage('Tasker - Home');
		return widgetMessages;
	},
	_load_tasker_home_icons: function(icons){
		icons["Home24.svg"] = this._buildIcon({imageName: 'Home24.svg', title: gs.getMessage("Tasker - Home"), alt: ""});	
		return icons;
	},
	_load_tasker_home_defaultsAndSettings: function($sp){
		settings = {};
		settings.baseURL = gs.getProperty('glide.servlet.uri');
		if($sp.getPortalRecord()){
			settings.service_portal_url_suffix = $sp.getPortalRecord().getValue('url_suffix');
		} else {
			// TODO: May want to pull default from the form load here
			settings.service_portal_url_suffix = '';
		}


		return settings;
	},
	// ------------------------------------------------------------------------------------------------------------------
	// END  - Tasker Home Icon
	// ------------------------------------------------------------------------------------------------------------------	

	// ------------------------------------------------------------------------------------------------------------------
	// BEGIN - Tasker Portal Board with Filter
	// ------------------------------------------------------------------------------------------------------------------	
	_load_tasker_count_widgetMessages: function(){
		var widgetMessages = {};
		return widgetMessages;
	},
	_load_tasker_count_icons: function(icons){
		// not using this for count b/c each instance uses a different icon.  
		// so, Icons are just loaded from the options for now
		return icons;
	},

	_load_tasker_count_defaultsAndSettings: function($sp){
		settings = {};

		// load current page from URL, last saved, or default
		settings.userDefaultLandingPage = this._getFilterPage($sp);

		// load the default filter for the current page
		settings.userDefaultMainFilter = this._getSelectedFitlerTitle(settings.userDefaultLandingPage);
		return settings;

	},
	// ------------------------------------------------------------------------------------------------------------------
	// END  - Tasker Portal Board with Filter
	// ------------------------------------------------------------------------------------------------------------------	

	// ------------------------------------------------------------------------------------------------------------------
	// BEGIN - Tasker Count
	// ------------------------------------------------------------------------------------------------------------------	
	_load_tasker_portal_board_with_filter_widgetMessages: function(){
		var widgetMessages = {};
		return widgetMessages;
	},
	_load_tasker_portal_board_with_filter_icons: function(icons){
		// not using this for count b/c each instance uses a different icon.  
		// so, Icons are just loaded from the options for now
		return icons;
	},

	_load_tasker_portal_board_with_filter_defaultsAndSettings: function($sp){
		settings = {};

		// load current page from URL, last saved, or default
		settings.userDefaultLandingPage = this._getFilterPage($sp);

		// load the default filter for the current page
		settings.userDefaultMainFilter = this._getSelectedFitlerTitle(settings.userDefaultLandingPage);
		return settings;

	},
	// ------------------------------------------------------------------------------------------------------------------
	// END - Tasker Header Menu
	// ------------------------------------------------------------------------------------------------------------------	
	// ------------------------------------------------------------------------------------------------------------------
	// BEGIN - Tasker Header Menu
	// ------------------------------------------------------------------------------------------------------------------	
	_load_tasker_header_menu_widgetMessages: function(){
		var widgetMessages = {};
		return widgetMessages;
	},
	_load_tasker_header_menu_icons: function(icons){
		// STRY0121811 
		icons["Divider_Black.svg"] = this._buildIcon({imageName: 'Divider_Black.svg', title: "", alt: ""});
		// this widget expcts .svg to be returned in the icon name b/c that is what is in the menu item
		icons["NewTask24.svg"] = this._buildIcon({imageName: 'NewTask24.svg', title: gs.getMessage("Tasker - New Task"), alt: ""});	
		icons["NewTemplate24.svg"] = this._buildIcon({imageName: 'NewTemplate24.svg', title: gs.getMessage("Tasker - New Template"), alt: ""});	
		icons["Task_Black24.svg"] = this._buildIcon({imageName: 'Task_Black24.svg', title: gs.getMessage("Tasker - Task_Black24.svg"), alt: ""});
		icons["TaskManager_Black24.svg"] = this._buildIcon({imageName: 'TaskManager_Black24.svg', title: gs.getMessage("Tasker - TaskManager_Black24.svg"), alt: ""});
		icons["Template24.svg"] = this._buildIcon({imageName: 'Template24.svg', title: gs.getMessage("Tasker - Templates"), alt: ""});	
		icons["Office_Black24.svg"] = this._buildIcon({imageName: 'Office_Black24.svg', title: gs.getMessage("Tasker - Organizational Hierarchy"), alt: ""});
		icons["Dashboard24.svg"] = this._buildIcon({imageName: 'Dashboard24.svg', title: gs.getMessage("Tasker - Dashboard"), alt: ""});	

		icons["MyTasks16.svg"] = this._buildIcon({imageName: 'MyTasks16.svg', title: gs.getMessage("Tasker - MyTasks16.svg"), alt: ""});
		icons["Office16.svg"] = this._buildIcon({imageName: 'Office16.svg', title: gs.getMessage("Tasker - Office16.svg"), alt: ""});

		// STRY0123377
		icons["Task_Black16.svg"] = this._buildIcon({imageName: 'Task_Black16.svg', title: gs.getMessage("Tasker - Task_Black16.svg"), alt: ""});
		icons["TaskManager_Black16.svg"] = this._buildIcon({imageName: 'TaskManager_Black16.svg', title: gs.getMessage("Tasker - TaskManager_Black16.svg"), alt: ""});
		icons["TaskAdministrator_Black16.svg"] = this._buildIcon({imageName: 'TaskAdministrator_Black16.svg', title: gs.getMessage("Tasker - TaskAdministrator_Black16.svg"), alt: ""});	
		icons["ApplicationStatus16.svg"] = this._buildIcon({imageName: 'ApplicationStatus16.svg', title: gs.getMessage("Tasker - ApplicationStatus16.svg"), alt: ""});




		icons["Search24.svg"] = this._buildIcon({imageName: 'Search24.svg', title: gs.getMessage("Tasker - Search"), alt: ""});	

		icons["Placeholder16.svg"] = this._buildIcon({imageName: 'Placeholder16.svg', title: gs.getMessage("Tasker - Placeholder16.svg"), alt: ""});	
		return icons;
	},
	_load_tasker_header_menu_defaultsAndSettings: function($sp){
		settings = {};

		var orgUserDefaultPageId = gs.getUser().getPreference(this.ORG_USER_DEFAULT_PAGE_ID);
		if(orgUserDefaultPageId){
			settings.orgUserDefaultPageId = orgUserDefaultPageId;
		} else {
			// leave this undefined so the default on the menu item is used
			settings.orgUserDefaultPageId = undefined;
		}
		// load current page from URL, last saved, or default
		settings.userDefaultLandingPage = this._getFilterPage($sp);

		// load the default filter for the current page
		settings.userDefaultMainFilter = this._getSelectedFitlerTitle(settings.userDefaultLandingPage);		
		return settings;

	},
	// ------------------------------------------------------------------------------------------------------------------
	// END - Tasker Header Menu
	// ------------------------------------------------------------------------------------------------------------------
	// ------------------------------------------------------------------------------------------------------------------
	// BEGIN - Default Tool Tip section
	// ------------------------------------------------------------------------------------------------------------------
	_load_toolTip_footer_widgetMessages: function(){
		var widgetMessages = {};
		widgetMessages['Tasker - Entire Tree'] = gs.getMessage('Tasker - Entire Tree');
		widgetMessages['Tasker - Custom Zoom'] = gs.getMessage('Tasker - Custom Zoom');

		return widgetMessages;
	},	

	// DFCT0010944 - "Tree Zoom Option" tooltips are incorrect on "Template", "Template Task", "Task" forms
	// ORG settings were moved out of this tooltip load.
	_load_tree_footer_icons: function(icons){
		icons["Divider_Black"] = this._buildIcon({imageName: 'Divider_Black.svg', title: "", alt: ""});		
		icons["ZoomEntire24"] = this._buildIcon({imageName: 'ZoomEntire24.svg', title: gs.getMessage("Tasker - View the Entire Tree"), alt: gs.getMessage("Tasker - View the Entire Tree")});
		icons["ZoomSelected24"] = this._buildIcon({imageName: 'ZoomSelected24.svg', title: gs.getMessage("Tasker - Zoom into Selected Task"), alt: gs.getMessage("Tasker - Selected OU")});
		icons["Top24"] = this._buildIcon({imageName: 'TopOU24.svg', title: gs.getMessage("Tasker - Navigate to Top"), alt: gs.getMessage("Tasker - Go to Top")});
		return icons;
	},

	_load_tree_header_defaultsAndSettings: function($sp){
		settings = {};

		var treePreference = this.PREFERENCE_TREE_ORIENTATION + "." + this.getTopId();
		var treeOrientation = gs.getUser().getPreference(treePreference);
		if(treeOrientation){
			settings.treeOrientation = treeOrientation;
		} else {
			// get the default
			var defaultIsVertical = new tasking_System_Settings_Scripts().systemControlSetting().VerticalTree;
			if(defaultIsVertical){
				settings.treeOrientation = "Vertical";
			} else {
				settings.treeOrientation = "Horizontal";
			}
		}
		return settings;

	},
	_load_tree_footer_defaultsAndSettings: function(){
		settings = {};
		var treePercent = this.PREFERENCE_PERCENT + "." + this.getTopId();
		var diagramScale = gs.getUser().getPreference(treePercent);
		if(diagramScale){
			settings.diagramScale = diagramScale;
		} else {
			settings.diagramScale = 1.0;
		}
		return settings;
	},

	// ------------------------------------------------------------------------------------------------------------------
	// END - Default Tool Tip section
	// ------------------------------------------------------------------------------------------------------------------
	// ------------------------------------------------------------------------------------------------------------------
	// BEGIN - Template Tree section
	// ------------------------------------------------------------------------------------------------------------------
	// DFCT0010944 - "Tree Zoom Option" tooltips are incorrect on "Template", "Template Task", "Task" forms
	_load_template_tree_header_icons: function(icons){
		// NOTE the icons are the same inside of the template tree, but the text is diffrent
		icons["OrgHierarchy24"] = this._buildIcon({imageName: 'OrgHierarchy24.svg', title: gs.getMessage("Tasker - View as Horizontal Structure"), alt: gs.getMessage("Tasker - View as Horizontal Structure")});
		icons["OrgHierarchy-Vertical24"] = this._buildIcon({imageName: 'OrgHierarchy-Vertical24.svg', title: gs.getMessage("Tasker - View as Vertical Structure"), alt: gs.getMessage("Tasker - View as Vertical Structure")});
		icons["Divider_Black"] = this._buildIcon({imageName: 'Divider_Black.svg', title: "", alt: ""});
		return icons;
	},

	_load_template_defaultsAndSettings: function($sp){
		settings = {};
