	_load_officehierarchy_defaultsAndSettings: function($sp){
		settings = {};
		settings.page_id = $sp.getParameter("id");

		// TODO - GET THIS SETTING FROM THE OPTIONS INSTEAD OF LOOKING AT A PAGE ID
		// ONCE COMING FROM OPTIOIN, UPDATE THIS SETTING TO NOT USE PAGE ID, UPDATE
		// ALL PAGES WHERE FULL SCREEN DESIRED TO TRUE AND THE REST SHOULD BE FINE
		settings.isFullScreen = settings.page_id == 'discovertasker_ouhierarchy_full_screeen';
		settings.permissiveOn = gs.getProperty('x_153465_discovert.PermissiveOUTaskingOptions') != 'Off';
		settings.baseURL = gs.getProperty('glide.servlet.uri');
		if($sp.getPortalRecord()){
			settings.service_portal_url_suffix = $sp.getPortalRecord().getValue('url_suffix');
		} else {
			// TODO: May want to pull default from the form load here
			settings.service_portal_url_suffix = '';
		}
		// TODO - ADD TO WIDGET OPTIONS - LEFT OFF FOR NOW
		settings.include_poc_avatar = true;

		// STRY0074597 default to true, will change later if input
		settings.topOnly = true;
		var count = new GlideAggregate('x_153465_discovert_discover_office_hierarchy');
		// DFCT0010275 - use addNullQuery for a null query instead of a string value
		count.addNullQuery('parent');
		count.addAggregate('COUNT');
		count.query();
		var topHierarchy = 0;
		if(count.next())
			topHierarchy = count.getAggregate('COUNT');
		settings.topParentNeeded = topHierarchy < 1;
		return settings;
	},

