	// note this is different than other setting loads as it takes settings because the standard footer settings is loaded first
	_load_ORG_tooltip_footer_defaultsAndSettings: function(settings, $sp){
		// getDefaultId for user
		var orgScripts = new OrganizationalScripts();
		var defaultOUId = orgScripts.GetUserDefaultOU(gs.getUserID()) + '';
		// get top ou for the user based on default id
		var defaultOUTopId =orgScripts.getTopOUId(defaultOUId);
		settings.defaultOU = {value: defaultOUId, topId: defaultOUTopId};

		var favoriteOU = gs.getUser().getPreference(this.PREFERENCE_FAVORITE);
		if(favoriteOU){
			settings.favorite = JSON.parse(favoriteOU);
		} else {
			settings.favorite = {value: "",	topId: ""};
		}


		// STRY0121023 
		var favoriteOUStopPrompt = gs.getUser().getPreference(this.PREFERENCE_FAVORITE_STOP_PROMPT);
		if(favoriteOUStopPrompt){
			settings.favoriteStopPrompt = true;
		} else {
			settings.favoriteStopPrompt = undefined;
		}

		// STRY0121017 
		var defaultOUStopPrompt = gs.getUser().getPreference(this.PREFERENCE_DEFAULT_STOP_PROMPT);
		if(defaultOUStopPrompt){
			settings.defaultStopPrompt = true;
		} else {
			settings.defaultStopPrompt = undefined;
		}


		return settings;
	},

